const test = require("node:test");
const assert = require("node:assert");
const { slugify, titleCase } = require("../src/strings.js");

test("slugify kebabs spaces and underscores", () => {
  assert.strictEqual(slugify("Hello World"), "hello-world");
  assert.strictEqual(slugify("A_B c"), "a-b-c");
  assert.strictEqual(slugify("Cool! Stuff?"), "cool-stuff");
});

test("titleCase capitalizes each word", () => {
  assert.strictEqual(titleCase("ada lovelace"), "Ada Lovelace");
  assert.strictEqual(titleCase("GRACE hopper"), "Grace Hopper");
});
